proof fn phi_1_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.implies(q).satisfied_by(ex),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_2_implies_contraposition_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.implies(q).satisfied_by(ex),
        not(q).satisfied_by(ex),
    ensures
        not(p).satisfied_by(ex),
{
    implies_contraposition_apply::<int>(ex, p, q);
}

proof fn phi_3_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_4_extensional_equality_of_spec_fn(f: spec_fn(Execution<int>) -> bool, g: spec_fn(Execution<int>) -> bool)
    requires
        forall |ex: Execution<int>| f(ex) ==> g(ex),
        forall |ex: Execution<int>| g(ex) ==> f(ex),
    ensures
        f == g,
{
    let p = TempPred::<int> { pred: f };
    let q = TempPred::<int> { pred: g };
    temp_pred_equality::<int>(p, q);
}

proof fn phi_5_not_not_equals_self(p: TempPred<int>)
    ensures
        not(not(p)) == p,
{
    temp_pred_equality::<int>(not(not(p)), p);
}
